  struct
    type nonrec t =
      {
      instanceEventId: InstanceEventId.t option
        [@ocaml.doc "The ID of the event."];
      code: EventCode.t option [@ocaml.doc "The event code."];
      description: String_.t option
        [@ocaml.doc
          "A description of the event. After a scheduled event is completed, it can still be described for up to a week. If the event has been completed, this description starts with the following text: \\[Completed\\]."];
      notAfter: DateTime.t option
        [@ocaml.doc "The latest scheduled end time for the event."];
      notBefore: DateTime.t option
        [@ocaml.doc "The earliest scheduled start time for the event."];
      notBeforeDeadline: DateTime.t option
        [@ocaml.doc "The deadline for starting the event."]}
    let make ?instanceEventId =
      fun ?code ->
        fun ?description ->
          fun ?notAfter ->
            fun ?notBefore ->
              fun ?notBeforeDeadline ->
                fun () ->
                  {
                    instanceEventId;
                    code;
                    description;
                    notAfter;
                    notBefore;
                    notBeforeDeadline
                  }
    let to_value x =
      structure_to_value
        [("instanceEventId",
           (Option.map x.instanceEventId ~f:InstanceEventId.to_value));
        ("code", (Option.map x.code ~f:EventCode.to_value));
        ("description", (Option.map x.description ~f:String_.to_value));
        ("notAfter", (Option.map x.notAfter ~f:DateTime.to_value));
        ("notBefore", (Option.map x.notBefore ~f:DateTime.to_value));
        ("notBeforeDeadline",
          (Option.map x.notBeforeDeadline ~f:DateTime.to_value))]
    let to_query v = to_query to_value v
    let of_xml xml_arg0 =
      let notBeforeDeadline =
        (Option.map ~f:DateTime.of_xml)
          (Xml.child xml_arg0 "notBeforeDeadline") in
      let notBefore =
        (Option.map ~f:DateTime.of_xml) (Xml.child xml_arg0 "notBefore") in
      let notAfter =
        (Option.map ~f:DateTime.of_xml) (Xml.child xml_arg0 "notAfter") in
      let description =
        (Option.map ~f:String_.of_xml) (Xml.child xml_arg0 "description") in
      let code = (Option.map ~f:EventCode.of_xml) (Xml.child xml_arg0 "code") in
      let instanceEventId =
        (Option.map ~f:InstanceEventId.of_xml)
          (Xml.child xml_arg0 "instanceEventId") in
      make ?notBeforeDeadline ?notBefore ?notAfter ?description ?code
        ?instanceEventId ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let notBeforeDeadline =
        field_map json__ "NotBeforeDeadline" DateTime.of_json in
      let notBefore = field_map json__ "NotBefore" DateTime.of_json in
      let notAfter = field_map json__ "NotAfter" DateTime.of_json in
      let description = field_map json__ "Description" String_.of_json in
      let code = field_map json__ "Code" EventCode.of_json in
      let instanceEventId =
        field_map json__ "InstanceEventId" InstanceEventId.of_json in
      make ?notBeforeDeadline ?notBefore ?notAfter ?description ?code
        ?instanceEventId ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc "Describes a scheduled event for an instance."]
